def lcs_length(a, b):
    # dynamic programming LCS length
    # But for long strings, dynamic programming O(n*m). Strings are short; fine.
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = dp[j] if dp[j] >= dp[j-1] else dp[j-1]
            prev = tmp
    return dp[m]

def lcs_norm_sim(a, b):
    # normalized LCS similarity: 2*LCS / (len(a)+len(b))
    a = a.strip()
    b = b.strip()
    if not a or not b:
        return 0.0
    l = lcs_length(a, b)
    return 2*l / (len(a) + len(b))

def token_f1(a, b):
    ta = a.split()
    tb = b.split()
    if not ta or not tb:
        return 0.0
    ca = Counter(ta)
    cb = Counter(tb)
    common = sum((ca & cb).values())
    prec = common / len(ta)
    rec = common / len(tb)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

